import{_ as e,o as s,c as a,a2 as t}from"./chunks/framework.D6hBiDio.js";const m=JSON.parse('{"title":"Memory Optimization","description":"Reduce Tailscale memory usage with GOGC tuning for low-RAM devices","frontmatter":{"title":"Memory Optimization","description":"Reduce Tailscale memory usage with GOGC tuning for low-RAM devices"},"headers":[],"relativePath":"en/guide/oom.md","filePath":"en/guide/oom.md","lastUpdated":1784575673000}'),l={name:"en/guide/oom.md"};function n(o,i,r,d,p,h){return s(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="memory-optimization" tabindex="-1">Memory Optimization <a class="header-anchor" href="#memory-optimization" aria-label="Permalink to &quot;Memory Optimization&quot;">​</a></h1><p>If your device has limited RAM, Tailscale may consume excessive memory or get killed by the OOM Killer. You can reduce memory usage by adjusting the GOGC parameter.</p><h2 id="symptoms" tabindex="-1">Symptoms <a class="header-anchor" href="#symptoms" aria-label="Permalink to &quot;Symptoms&quot;">​</a></h2><p>You might need this optimization if:</p><ul><li>Your device has limited RAM and Tailscale consumes too much memory</li><li>Tailscale is killed and restarted by the OOM Killer</li><li>Tailscale keeps restarting unexpectedly</li></ul><h2 id="solution-adjust-gogc" tabindex="-1">Solution: Adjust GOGC <a class="header-anchor" href="#solution-adjust-gogc" aria-label="Permalink to &quot;Solution: Adjust GOGC&quot;">​</a></h2><ol><li>Edit the init script:</li></ol><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/init.d/tailscale</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="2"><li>Find this line:</li></ol><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">procd_set_param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TS_DEBUG_FIREWALL_MODE=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$fw_mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="3"><li>Append <code>GOGC=10</code> to the end of that line:</li></ol><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">procd_set_param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TS_DEBUG_FIREWALL_MODE=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$fw_mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GOGC=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="4"><li>Restart Tailscale:</li></ol><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/init.d/tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ul><li><code>GOGC=10</code> tells the Go runtime to trigger GC when heap grows by 10% (default is 100%)</li><li>More frequent but smaller GC cycles</li><li><strong>Trade-off</strong>: Higher CPU usage, lower peak memory</li><li>Suitable for devices with limited RAM (128MB or less)</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Setting GOGC too low (&lt; 5) may cause performance degradation. Start with 10 and adjust as needed.</p></div>',17)])])}const u=e(l,[["render",n]]);export{m as __pageData,u as default};
